   176	                                  IProgress<int> progress,
   177	                                  [NotNullWhen(false)]
   178	                                  out string?    failureReason)
   179	        {
   180	            var origPath  = Configuration.DownloadCacheDir;
   181	            var origCache = Cache;
   182	            try
   183	            {
   184	                if (path is { Length: > 0 })
   185	                {
   186	                    Cache = new NetModuleCache(this, path);
   187	                    if (path != origPath)
   188	                    {
