   194	                    Directory.CreateDirectory(DefaultDownloadCacheDir);
   195	                    Cache = new NetModuleCache(this, DefaultDownloadCacheDir);
   196	                    Configuration.DownloadCacheDir = null;
   197	                }
   198	                if (origPath != null && origCache != null && path != origPath)
   199	                {
   200	                    origCache.GetSizeInfo(out _, out long oldNumBytes, out _);
   201	                    Cache.GetSizeInfo(out _, out _, out long? bytesFree);
   202	
   203	                    if (oldNumBytes > 0)
   204	                    {
   205	                        switch (User.RaiseSelectionDialog(
   206	                                    bytesFree.HasValue
   207	                                        ? string.Format(Properties.Resources.GameInstanceManagerCacheMigrationPrompt,
