   209	                                                        CkanModule.FmtSize(bytesFree.Value))
   210	                                        : string.Format(Properties.Resources.GameInstanceManagerCacheMigrationPromptFreeSpaceUnknown,
   211	                                                        CkanModule.FmtSize(oldNumBytes)),
   212	                                    oldNumBytes < (bytesFree ?? 0) ? 0 : 2,
   213	                                    Properties.Resources.GameInstanceManagerCacheMigrationMove,
   214	                                    Properties.Resources.GameInstanceManagerCacheMigrationDelete,
   215	                                    Properties.Resources.GameInstanceManagerCacheMigrationOpen,
   216	                                    Properties.Resources.GameInstanceManagerCacheMigrationNothing,
   217	                                    Properties.Resources.GameInstanceManagerCacheMigrationRevert))
   218	                        {
   219	                            case 0:
   220	                                if (oldNumBytes < bytesFree)
   221	                                {
   222	                                    Cache.MoveFrom(new DirectoryInfo(origPath), progress);
   223	                                    CacheChanged?.Invoke(origCache);
   224	                                    origCache.Dispose();
   225	                                }
   226	                                else
   227	                                {
   228	                                    User.RaiseError(Properties.Resources.GameInstanceManagerCacheMigrationNotEnoughFreeSpace);
   229	                                    // Abort since the user picked an option that doesn't work
   230	                                    Cache = origCache;
